	s.mu.RLock()
	defer s.mu.RUnlock()
	return s.outcome.Clone()
}

func (s *reloadOutcomeStore) Record(outcome web.ReloadOutcome, logger *slog.Logger) {
	s.mu.Lock()
	s.outcome = outcome.Clone()
	b, err := json.Marshal(s.outcome)
	if err == nil {
		err = os.MkdirAll(filepath.Dir(s.path), 0o755)
	}
	if err == nil {
		err = os.WriteFile(s.path, b, 0o644)
	}
	s.mu.Unlock()
	if err != nil {
		logger.Warn("Unable to persist reload outcome", "err", err)
	}
